const { execSync } = require('child_process');
try {
  // 先创建全局技能目录
  execSync('mkdir -p ~/.skillhub/skills', { encoding: 'utf8' });

  // 安装到全局目录
  const result = execSync('skillhub install chat --dir ~/.skillhub/skills --force', { 
    cwd: '/Users/orion/Documents/Flutter/llmchat', 
    encoding: 'utf8' 
  });
  console.log(result);

  // 验证安装
  const result2 = execSync('ls -la ~/.skillhub/skills/chat/', { encoding: 'utf8' });
  console.log('全局安装位置内容:');
  console.log(result2);
} catch(e) {
  console.log('stdout:', e.stdout || '');
  console.log('stderr:', e.stderr || '');
}
